    workflowStaticData.telegramStates = {};
}
workflowStaticData.telegramStates[$json.message.chat.id.toString()] = { waitingPhoto: true };
return $input.all();

let globalData = $getWorkflowStaticData('global');
let state = "none"; // Default state

if (globalData && globalData.telegramStates) {
    let chatData = globalData.telegramStates[$json.message.chat.id.toString()];
    if (chatData) {
        if (chatData.waitingShipmentNumber === true) {
            state = "waitingShipmentNumber";
        } else if (chatData.waitingGPS === true) {
            state = "waitingGPS";
        } else if (chatData.waitingPhoto === true) {
            state = "waitingPhoto";
        }
    }
}
return { state };

let workflowData = $getWorkflowStaticData('global');

// Extract the file link from Google Drive node
let fileLink = $('Upload Picture').first().json.webContentLink || "No link available";
let fileId = $('Upload Picture').first().json.id || "No ID available";
// Public Link
let publicImageLink = `{{ $env.WEBHOOK_URL }}{fileId}`;
let deliveryTime = $now

// Store the link in static data
workflowData.fileLink = fileLink;
workflowData.publicImageLink = publicImageLink;
workflowData.deliveryTime = deliveryTime
return {
    fileLink: fileLink,
    publicImageLink: publicImageLink,
    deliveryTime: deliveryTime
};

